1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const BLOCK_OF_3_PRICE = 60;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	};
12	
13	export function processScenario(scenario: any): any {
14	  const step = scenario.steps[0];
15	  let basePremium = 0;
16	  const typeCounts: Record<string, number> = {};
17	  for (const item of step.items) {
18	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
19	  }
20	  for (const [type, count] of Object.entries(typeCounts)) {
21	    const isComponentType = BASE_PREMIUM[type] === 25;
22	    const formsBlockOf3 = count === 3 && isComponentType;
23	    if (formsBlockOf3) {
24	      basePremium += BLOCK_OF_3_PRICE;
25	    } else {
26	      basePremium += count * BASE_PREMIUM[type];
27	    }
28	  }
29	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
30	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
31	  return { results: [{ premium }] };
32	}
